+import { $internal } from '../common';
+import type { Entity } from '../entity/types';
+import { getEntityId } from '../entity/utils/pack-entity';
+import { hasTrait } from '../trait/trait';
+import type { Trait } from '../trait/types';
+import type { World } from '../world';
+import type { PredicateModifier, QueryInstance } from './types';
+
+function matches(world: World, entity: Entity, modifier: PredicateModifier): boolean {
+    const eid = getEntityId(entity);
+    for (const trait of modifier.traits) if (!hasTrait(world, entity, trait)) return false;
+    return modifier.predicate(modifier.traits.map((trait) => {
+        const instance = world[$internal].traitInstances.get(trait)!;
+        return trait[$internal].get(eid, instance.store);
+    }));
+}
+
+export function updatePredicateQueries(world: World, entity: Entity, trait: Trait) {
+    const instance = world[$internal].traitInstances.get(trait);
+    if (!instance) return;
+    const queries = new Set<QueryInstance>([...instance.queries, ...instance.trackingQueries]);
+    const eid = getEntityId(entity);
+    for (const query of queries) {
+        for (const modifier of query.predicateModifiers) {
+            if (!modifier.traits.includes(trait)) continue;
+            const states = query.predicateStates.get(modifier)!;
+            const previous = states[eid] ?? false;
+            const next = matches(world, entity, modifier);
+            states[eid] = next;
+            const tracking = modifier.type.startsWith('added-')
+                ? !previous && next
+                : modifier.type.startsWith('removed-')
+                  ? previous && !next
+                  : modifier.type.startsWith('changed-')
+                    ? previous !== next
+                    : next;
+            const staticMatch = query.checkStatic(world, entity);
+            if (tracking && staticMatch) query.add(entity);
+            else if (!next || !staticMatch) query.remove(world, entity);
+        }
+    }
+}
