+import { Added, Changed, createAdded, createChanged, createPredicate, createRemoved, createWorld, Not, Or, Removed, trait } from '../src';
+
+describe('predicates', () => {
+    const Score = trait({ value: 0 });
+    const Other = trait({ value: 0 });
+
+    it('filters by dependency values and re-evaluates on add and set', () => {
+        const world = createWorld();
+        const High = createPredicate([Score], ([score]) => score.value > 5);
+        const entity = world.spawn(Score({ value: 2 }));
+        expect(world.query(High)).toEqual([]);
+        world.set(entity, Score, { value: 6 });
+        expect(world.query(High)).toEqual([entity]);
+        world.set(entity, Score, { value: 1 });
+        expect(world.query(High)).toEqual([]);
+    });
+
+    it('composes with Not and Or without adding callback data', () => {
+        const world = createWorld();
+        const High = createPredicate([Score], ([score]) => score.value > 5);
+        const entity = world.spawn(Score({ value: 6 }));
+        expect(world.query(Or(High), Not(Other))).toEqual([entity]);
+        world.query(High, Score).readEach(([score]) => expect(score.value).toBe(6));
+    });
+
+    it('tracks predicate truthiness transitions', () => {
+        const world = createWorld();
+        const High = createPredicate([Score], ([score]) => score.value > 5);
+        const Added = createAdded();
+        const Removed = createRemoved();
+        const Changed = createChanged();
+        const entity = world.spawn(Score({ value: 1 }));
+        expect(world.query(Added(High))).toEqual([]);
+        world.set(entity, Score, { value: 6 });
+        expect(world.query(Added(High))).toEqual([entity]);
+        expect(world.query(Changed(High))).toEqual([entity]);
+        world.set(entity, Score, { value: 1 });
+        expect(world.query(Removed(High))).toEqual([entity]);
+        expect(world.query(Changed(High))).toEqual([entity]);
+    });
